#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100005

// Define the structure for a soldier
typedef struct Soldier {
    int skill;
    int* subordinates;
    int numSubordinates;
} Soldier;

// Function to perform DFS and calculate the sum of skill levels for each soldier
void dfs(Soldier* soldiers, int currentSoldier) {
    // Initialize the sum of skill levels for the current soldier
    int sum = soldiers[currentSoldier].skill;

    // Iterate over the subordinates of the current soldier
    for (int i = 0; i < soldiers[currentSoldier].numSubordinates; i++) {
        int subordinate = soldiers[currentSoldier].subordinates[i];
        dfs(soldiers, subordinate);
        sum += soldiers[subordinate].skill;
    }

    // Update the sum of skill levels for the current soldier
    soldiers[currentSoldier].skill = sum;
}

int main() {
    int N, M;
    scanf("%d %d", &N, &M);

    // Initialize the soldiers array
    Soldier* soldiers = (Soldier*) malloc(N * sizeof(Soldier));

    // Read the skill levels of the soldiers
    for (int i = 0; i < N; i++) {
        scanf("%d", &soldiers[i].skill);
        soldiers[i].subordinates = NULL;
        soldiers[i].numSubordinates = 0;
    }

    // Read the hierarchy of the army
    for (int i = 0; i < N - 1; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        u--;
        v--;

        // Add v as a subordinate of u
        soldiers[u].subordinates = (int*) realloc(soldiers[u].subordinates, (soldiers[u].numSubordinates + 1) * sizeof(int));
        soldiers[u].subordinates[soldiers[u].numSubordinates] = v;
        soldiers[u].numSubordinates++;
    }

    // Perform DFS to calculate the sum of skill levels for each soldier
    dfs(soldiers, 0);

    // Process the queries
    for (int i = 0; i < M; i++) {
        char query[3];
        scanf("%s", query);

        if (query[0] == 'Q') {
            int S;
            scanf("%d", &S);
            S--;
            printf("%d\n", soldiers[S].skill);
        } else if (query[0] == 'U') {
            int S, x;
            scanf("%d %d", &S, &x);
            S--;
            soldiers[S].skill = x;
        }
    }

    return 0;
}

