import java.util.ArrayList;
import java.util.Scanner;

public class Main {
    // Define the structure for a soldier
    static class Soldier {
        int skill;
        ArrayList<Integer> subordinates;

        public Soldier() {
            subordinates = new ArrayList<>();
        }
    }

    // Function to perform DFS and calculate the sum of skill levels for each soldier
    public static void dfs(Soldier[] soldiers, int currentSoldier) {
        // Initialize the sum of skill levels for the current soldier
        int sum = soldiers[currentSoldier].skill;

        // Iterate over the subordinates of the current soldier
        for (int i = 0; i < soldiers[currentSoldier].subordinates.size(); i++) {
            int subordinate = soldiers[currentSoldier].subordinates.get(i);
            dfs(soldiers, subordinate);
            sum += soldiers[subordinate].skill;
        }

        // Update the sum of skill levels for the current soldier
        soldiers[currentSoldier].skill = sum;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int M = scanner.nextInt();

        // Initialize the soldiers array
        Soldier[] soldiers = new Soldier[N];
        for (int i = 0; i < N; i++) {
            soldiers[i] = new Soldier();
        }

        // Read the skill levels of the soldiers
        for (int i = 0; i < N; i++) {
            soldiers[i].skill = scanner.nextInt();
        }

        // Read the hierarchy of the army
        for (int i = 0; i < N - 1; i++) {
            int u = scanner.nextInt() - 1;
            int v = scanner.nextInt() - 1;

            // Add v as a subordinate of u
            soldiers[u].subordinates.add(v);
        }

        // Perform DFS to calculate the sum of skill levels for each soldier
        dfs(soldiers, 0);

        // Process the queries
        for (int i = 0; i < M; i++) {
            String query = scanner.next();

            if (query.equals("Q")) {
                int S = scanner.nextInt() - 1;
                System.out.println(soldiers[S].skill);
            } else if (query.equals("U")) {
                int S = scanner.nextInt() - 1;
                int x = scanner.nextInt();
                soldiers[S].skill = x;
            }
        }
    }
}

